// Count how often each brand appears (title/channel) in the results -> share-of-voice rows.
const data = $input.first().json;
const results = data.results || [];
const total = results.length || 1;
const cfg = $('Set Inputs').first().json;
const brands = cfg.brands || [];
const rows = brands.map((b) => {
  const term = String(b).toLowerCase();
  const matches = results.filter((r) => (((r.title || '') + ' ' + (r.channelTitle || '')).toLowerCase()).includes(term));
  const top = matches[0];
  return {
    brand: b,
    mentions: matches.length,
    sharePct: Math.round((matches.length / total) * 1000) / 10,
    topExampleTitle: top ? (top.title || null) : null,
    topExampleUrl: top ? ('https://www.youtube.com/watch?v=' + top.videoId) : null,
  };
});
rows.sort((a, b) => b.mentions - a.mentions);
return rows.map((r, i) => ({ json: { keyword: cfg.keyword, rank: i + 1, brand: r.brand, mentions: r.mentions, sharePct: r.sharePct, totalResults: results.length, topExampleTitle: r.topExampleTitle, topExampleUrl: r.topExampleUrl } }));
